-- Adicionar grupo muscular de membros inferiores
ON CONFLICT (id) DO NOTHING;

-- Exercícios de Membros Inferiores baseados nos GIFs do Supabase Storage
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, gif_path = EXCLUDED.gif_path, updated_at = NOW();

SELECT COUNT(*) as total_membros_inf FROM app_correcrat.exercises WHERE muscle_group_id = 'membros_inf';
